vector<string> uncommonFromSentences(string s1, string s2) {
    unordered_map<string, int> count;
    string word;
    for (char c : s1 + " " + s2) {
        if (c == ' ') {
            if (!word.empty()) {
                count[word]++;
                word.clear();
            }
        } else {
            word += c;
        }
    }
    if (!word.empty()) {
        count[word]++;
    }
    vector<string> result;
    for (auto& pair : count) {
        if (pair.second == 1) {
            result.push_back(pair.first);
        }
    }
    return result;
}
```

